@spec mm_reindex_if_stale_spec  src=tests/specs/mm_reindex_if_stale_spec.lua  loc=117  sha=70ef819  cases=5
@exercises midiManager (h.mm)
@surface   mm:events, mm:notesRaw, mm:reindexIfStale, mm:notes, mm:modify, mm:delete, mm:assign
@harness   bareMM

# Intent
  Pins the reindex gate: an add/ppq move unsorts, a delete holes, an assign touching neither
  skips the reindex outright -- and a missed flag fails silently. design/archive/incremental-rebuild.md § 6.

# Helpers
  @fn tokPpqs(mm)  @ 6-10
  @fn noteField(mm, field)  @ 12-16
  @fn pair(harness)  @ 18-23
  @fn uuidAtPpq(mm, ppq)  @ 25-27

# Cases
  @case 'reindexIfStale() is a no-op on already-compact state'  [harness]  @ 31-45
  @case 'reindexIfStale() stays inert after a compacting modify'  [harness]  @ 49-63
  @case 'a value-only assign is index-clean: the verb keeps its own index, nothing launders it'  [harness]  @ 67-86
  @case 'a ppq move re-sorts the arrays; it leaves no hole to compact'  [harness]  @ 90-99
  @case 'an add sorts into place; a delete compacts around the hole'  [harness]  @ 103-115

# Uses (outbound edges)
  @use call mm:events  @ 8
  @use call mm:notesRaw  @ 14,26
  @use call mm:reindexIfStale  @ 43,61
  @use call mm:notes  @ 57
  @use call mm:modify  @ 58,75,79,94,106,112
  @use call mm:delete  @ 58,112
  @use call mm:assign  @ 75,79,94
